try { result2 = operation2(); } catch (Exception ex) { lastError = ex; }
try { result3 = operation3(); } catch (Exception ex) { lastError = ex; }

if (lastError != null)
{
    MessageBox.Show("An error occurred: " + lastError.Message);
    lastError = null;
}

